var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"앗, 보라 씨. 오셨어요? 아카데미는 어떠셨나요?","JPN":"あっ、シホさん。おかえりなさい！　アカデミーはどうでしたか？","ENG":"Oh, Bora. You're back. How was the Academy?","TWN":"啊，寶拉。你來了？學院怎麼樣？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"학생들도 잘 따라줬고……. 보람 있었어요.","JPN":"生徒たちも協力してくれて……行った甲斐がありました。","ENG":"The students behaved well, and... it was rewarding.","TWN":"學生們都很配合……很有成就感。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"대단하시네요. 회사 일도 많이 바쁘실 텐데…….","JPN":"すごいですね。会社の仕事だけでもお忙しいのに……","ENG":"That's amazing. And you're still busy with work in the company...","TWN":"真了不起，公司事務應該也很忙吧……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아뇨……. 그렇지도 않아요.","JPN":"いいえ……そうでもありません。","ENG":"No... Not really.","TWN":"不……也不是那樣的。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"출근하셨나요……? 가람 씨는.","JPN":"出社してますか……？　ヒカリさん。","ENG":"Is she in...? Garam?","TWN":"嘉蘭……上班了嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"네. 자리에 계세요.","JPN":"はい、席にいます。","ENG":"Yes. She's in her seat.","TWN":"是的，在座位上呢。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"하…… 회의는 매번 긴장된다니까…….","JPN":"はあ……会議は何度参加しても緊張する……","ENG":"*Sigh* I always get nervous at meetings...","TWN":"哈……每次開會都搞得我很緊張……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"가람 씨.","JPN":"ヒカリさん。","ENG":"Garam.","TWN":"嘉蘭。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"먼저 가 있을까요……? 회의.","JPN":"先に行きますか……会議。","ENG":"Should I wait for you... for the meeting?","TWN":"會議……先過去嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아, 선배! 오셨어요?","JPN":"あ、先輩！　いたんですね。","ENG":"Oh, Bora! You're here.","TWN":"啊，前輩！你來了？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"긴장하지 마요……. 너무.","JPN":"あまり……緊張しないで。","ENG":"Don't be too... nervous.","TWN":"沒事，不要太緊張。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"잘 봐줄 테니까…… 옆에서.","JPN":"見てるから……そばで。","ENG":"I'll be right... by your side.","TWN":"我會好好看著你的……就在旁邊。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이, 이젠 저도 잘할 수 있어요!","JPN":"わ、私だって1人で上手くできますから！","ENG":"I-I can do this alone!","TWN":"我，我可以的！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"정말…… 언제까지 애 취급하시는 건지…….","JPN":"もう……いつまで子ども扱いするつもりなんだろ……","ENG":"Ugh... When will you stop treating me like a kid...?","TWN":"真是的……到底要把我當小朋友到什麼時候……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"회의 참석해 주셔서 감사합니다. 그럼 바로 진행할게요.","JPN":"会議にご参加いただきありがとうございます。では早速はじめさせていただきます。","ENG":"Thank you all for coming to this meeting. We will start right away.","TWN":"感謝各位參加會議，那我們就直接開始吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오늘 회의는 카운터즈 레거시의 성과 보고입니다.","JPN":"本日の議題は、カウンターズ・レガシーの成果報告となります。","ENG":"The agenda today is the results from Counters Legacy.","TWN":"今天的會議是制裁者的遺產成果報告。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오픈한지 얼마 안 됐음에도 프로젝트는 성공적이라 할 수 있겠어요.","JPN":"オープンしたばかりですが、プロジェクトは成功していると言えます。","ENG":"Even though it was only recently launched, the project can be said to be successful.","TWN":"雖然剛剛開始不久，但可以說專案是成功的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아카데미는 물론, 오픈 베타를 진행한 그라운드 원 유저들의 반응도 뜨거워요.","JPN":"アカデミーはもちろん、オープンベータを行ったグラウンド・ワンのユーザーからも熱い反応を得ています。","ENG":"The responses from the Academy and Ground One users who participated in the open beta are overwhelmingly positive.","TWN":"不僅是學院玩家，進行開放測試的G1玩家反應也很熱烈。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이제 본격적으로 카운터즈 레거시를 확장해도 될 것 같아요.","JPN":"これで、本格的にカウンターズ・レガシーを拡張しても良いと判断しています。","ENG":"I think it's time to expand Counters Legacy.","TWN":"現在可以正式擴展制裁者的遺產了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그라운드 원에 콘솔 시설을 만들고, 넷튜버도 초청해 보도록 하죠.","JPN":"グラウンド・ワンにコンソール施設を設置し、ネットチューバ―も招待してみましょう。","ENG":"We will create a console center in Ground One and invite some NetTubers.","TWN":"在G1建立一個平台，並邀請一些網紅。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"넷튜버는 하트베리 분들을 초청해 진행할 계획입니다.","JPN":"ネットチューバ―は、ハートベリーの方々を招待する予定です。","ENG":"For the NetTubers, we are considering inviting HRT Berry.","TWN":"關於網紅，準備邀請愛心莓果進行直播。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그리고…… 새로운 컨텐츠를 준비해 봤어요.","JPN":"それから……新しいコンテンツを用意してみました。","ENG":"Also... we have prepared some new content.","TWN":"然後……我準備了新的內容。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"컨텐츠라면…… 어떤……?","JPN":"コンテンツ……どういう……？","ENG":"New content...? What kind...?","TWN":"內容的話……是什麼……？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시에 랭킹 시스템을 도입할 거예요.","JPN":"カウンターズ・レガシーにランキングシステムを導入します。","ENG":"We are going to implement a ranking system in Counters Legacy.","TWN":"制裁者的遺產將引入排名系統。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터 등급과 퀘스트 클리어 횟수가 랭킹 점수에 반영될 거예요.","JPN":"カウンターランクとクエストクリア回数が、ランキングポイントに反映される予定です。","ENG":"The rank score will reflect the Counter Grade and the amount of quests each user has cleared.","TWN":"制裁者等級和任務完成次數將會呈現在排名分數中。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"단, 주의해 주세요. 유저들 관계가 나빠지지 않게.","JPN":"でも、注意してください。ユーザー同士の関係に悪影響が出ないように……","ENG":"But please be careful. Not to ruin the relationship between users.","TWN":"但是，請注意。不要影響玩家之間的關係。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};